wait_for_server() {
  local port="$1"
  for _ in $(seq 1 240); do
    if curl -fsS "http://${HOST}:${port}/v1/models" >/dev/null 2>&1; then
      return 0
    fi
    sleep 2
  done
  echo "server on port ${port} did not become ready" >&2
  return 1
}

stop_server() {
  local pid="$1"
  if kill -0 "${pid}" >/dev/null 2>&1; then
    kill "${pid}" || true
    wait "${pid}" || true
  fi
}

preflight() {
  local target="${1:-all}"
  local missing=0
  local needs_runtime=1
  case "${target}" in
    prepare_manifest|select) needs_runtime=0 ;;
  esac
  if [[ "${needs_runtime}" == "1" ]]; then
    if ! command -v curl >/dev/null 2>&1; then
      echo "missing dependency: curl" >&2
      missing=1
    fi
    if ! command -v vllm >/dev/null 2>&1; then
      echo "missing dependency: vllm" >&2
      missing=1
    fi
    if ! command -v nvidia-smi >/dev/null 2>&1; then
      echo "missing dependency: nvidia-smi" >&2
      missing=1
    elif ! nvidia-smi >/dev/null 2>&1; then
      echo "nvidia-smi is present but not healthy" >&2
      missing=1
    fi
  fi
  for path in results/checkpoints/qwen3_moe_searched_no_gt065_max_retention_candidate /srv/home/bohanlyu/.cache/huggingface/hub/models--Qwen--Qwen3-Coder-30B-A3B-Instruct/snapshots/b2cff646eb4bb1d68355c01b18ae02e7cf42d120 /srv/home/bohanlyu/.cache/huggingface/hub/models--Qwen--Qwen3-30B-A3B-Instruct-2507/snapshots/0d7cf23991f47feeb3a57ecb4c9cee8ea4a17bfe prompts/qwen_moe_route_probe_prompts.jsonl; do
    if [[ ! -e "${path}" ]]; then
      echo "missing input: ${path}" >&2
      missing=1
    fi
  done
  if ! python scripts/audit_qwen3_moe_eval_manifest_preflight.py --eval-budget-dir results/qwen3_moe_eval_budget_plan --output-dir results/qwen3_moe_eval_manifest_preflight >/dev/null; then
    echo "eval manifest preflight failed" >&2
    missing=1
  elif ! python -c 'import json, pathlib, sys; p=pathlib.Path("results/qwen3_moe_eval_manifest_preflight/summary.json"); d=json.loads(p.read_text()); print("manifest sha:", d.get("manifest_sha256")); sys.exit(0 if d.get("status") == "task_manifest_ready" else 1)'; then
    echo "eval manifest preflight did not report task_manifest_ready" >&2
    missing=1
  fi
  case "${target}" in
    all|collect|prepare_manifest|sources|baseline|select|source_qwen3_30b_instruct|source_qwen3_30b_coder) ;;
    eval_*) ;;
    *)
      if [[ ! -f results/qwen3_moe_router_calibration_job/cache/router_calibration_cache.pt ]]; then
        echo "missing router calibration cache for target ${target}: results/qwen3_moe_router_calibration_job/cache/router_calibration_cache.pt" >&2
        missing=1
      fi
      ;;
  esac
  if [[ "${missing}" != "0" ]]; then
    return 1
  fi
}

